-- Enrichment marathon batch: Crater, Creately, Creatify, credit mapping, Cricket Health, Criteo, croc, Cron

-- ── Crater ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Crater is a free, open-source, self-hosted invoicing and billing application built with Laravel and Vue.js, aimed at freelancers and small businesses. It handles invoices, estimates, recurring billing, expense tracking, multi-currency support, and client and payment management without subscription costs. Official development slowed after 2021, and the community-maintained fork InvoiceShelf now continues the codebase with active updates.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (self-hosted); no vendor subscription fees, though users pay for their own hosting$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (open-source community project rather than a company)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed (distributed open-source project hosted on GitHub)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Crater Invoicing Software: Free Open-Source Invoice App$q$, seo_title),
  seo_meta_description = COALESCE($q$Crater is a free, open-source, self-hosted invoicing app for freelancers and small businesses. See features, pricing, and how it compares to InvoiceShelf.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Crater is a free, open-source invoicing and billing application originally released around 2019 by developers publishing under the crater-invoice-inc organization on GitHub, built using the Laravel PHP framework for its backend and Vue.js for its frontend, with companion mobile apps built in React Native. It is licensed under the GNU Affero General Public License version 3 (AGPLv3), meaning the source code is freely available to download, self-host, modify, and redistribute, provided that any hosted modifications are also made available under the same license. Crater is designed primarily for freelancers, consultants, and small businesses that want an invoicing tool without recurring software-as-a-service fees, as long as they are willing to install and maintain it themselves on their own server, a VPS, or a self-hosting platform such as Cloudron. Core functionality includes creating and sending professional invoices and estimates, converting estimates into invoices, setting up recurring or subscription-style invoices, recording payments against invoices, tracking business expenses, managing a client database, applying taxes and multiple currencies, and generating basic financial reports. The application supports PDF generation for invoices and estimates, customizable invoice templates, and a dashboard summarizing outstanding, paid, and overdue invoices. Because Crater is self-hosted, users are fully responsible for their own data, backups, security patching, and server costs, which distinguishes it from cloud invoicing tools like Zoho Invoice, Wave, or FreshBooks that host data on the vendor's infrastructure in exchange for a subscription fee. A significant fact for anyone evaluating Crater in 2026 is that its original repository entered a largely unsupported state after 2021, with infrequent commits and a backlog of open issues. In response, community members created InvoiceShelf, a hard fork of the Crater codebase, which has become the actively maintained continuation of the project, adding bug fixes, new features, and ongoing compatibility updates. Anyone deploying Crater fresh today is generally directed by the community to install InvoiceShelf instead, since it uses the same underlying data model and user interface. There is also an unrelated, differently branded commercial product called Crater Financial offering AI-powered accounts receivable and accounts payable automation, which should not be confused with the open-source Crater invoicing app covered here, since the two share a name but are separate products from separate teams. For SEO and directory purposes, the open-source Crater invoicing application is the entity most commonly referenced when people search for Crater invoicing or Crater app, and it remains a commonly cited example of self-hosted, no-subscription invoicing software in comparison articles and open-source software directories such as AlternativeTo and SourceForge. Because there is no central vendor, there is no traditional customer support, sales team, headquarters, or disclosed company size; support instead comes from GitHub issues, community documentation at docs.craterapp.com, and increasingly, the InvoiceShelf community and documentation. Pricing is inherently free at the software license level; the only costs a user incurs are for hosting infrastructure (a low-cost VPS is typically sufficient) and their own time to install and maintain the application, typically via Docker, a LAMP or LEMP stack, or a one-click installer on platforms like Cloudron or CapRover.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '607fbb48-621c-4c7e-b652-55e4892d86ce';

