-- ── Criteo ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Criteo is a large, publicly traded advertising technology company (NASDAQ: CRTO) that operates a commerce media platform specializing in retargeting, retail media, and performance advertising. Founded in 2005 in Paris, France by Jean-Baptiste Rudelle, Franck Le Ouay, and Romain Niccoli, Criteo connects thousands of advertisers, retailers, and publishers to buy and sell commerce-focused digital advertising using first-party commerce data and AI-driven bidding. As of 2026 the company employs roughly 3,300 to 3,900 people worldwide and remains headquartered in Paris.$q$, short_description),
  pricing_model = COALESCE($q$Performance-based advertising platform, primarily cost-per-click and cost-per-impression bidding with a platform fee calculated as a percentage of media spend; not a flat-rate SaaS subscription$q$, pricing_model),
  starting_price = COALESCE($q$No fixed starting price; advertisers set their own budgets and CPC/CPM bids, with self-serve and managed-service options available$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE($q$Approximately 3,300 to 3,900 employees worldwide (varies by reporting period)$q$, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Criteo Review 2026: Commerce Media and Retargeting Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Criteo (NASDAQ: CRTO) is a commerce media and retargeting ad platform. Learn how it works, its pricing model, features, and history in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Criteo is a publicly traded advertising technology company, listed on NASDAQ under the ticker CRTO, that operates what it calls a commerce media platform connecting advertisers, retailers, and media owners around commerce-focused digital advertising. The company was founded in Paris, France in 2005 by Jean-Baptiste Rudelle, Franck Le Ouay, and Romain Niccoli, and it built its early reputation and much of its revenue on dynamic retargeting: showing personalized product ads to shoppers who had previously viewed items on a retailer's website but had not completed a purchase, using machine learning to predict which products and creative were most likely to drive a click and a sale. Criteo went public on NASDAQ in 2013 and remains headquartered in Paris, with a large global employee base reported at roughly 3,300 to 3,900 people depending on the reporting period, and offices across North America, Europe, and Asia-Pacific. Over time Criteo has broadened well beyond retargeting into a fuller commerce media and retail media business, rebranding its overall offering as the Commerce Media Platform. This platform includes a Commerce Media demand-side platform used by enterprise brands, retailers, and agencies to plan and buy commerce-focused advertising across a claimed network of more than 200 retailers and over 1,300 premium publishers; a next-generation supply-side platform, marketed as Commerce Grid, that lets media owners, agencies, and retailers connect their inventory and first-party commerce data to programmatic demand; and a Monetization Platform aimed at helping large retailers and marketplaces build and scale their own retail media networks, similar to what Amazon Ads or Walmart Connect operate internally. Criteo's pricing model is performance-based rather than a flat-rate software subscription: advertisers typically set daily or lifetime budgets and pay on a cost-per-click or cost-per-impression basis, with Criteo layering a platform fee calculated as a percentage of media spend on top of the underlying media cost; industry estimates put Criteo's effective revenue share in the rough range of 16 to 22 percent of ad spend, though exact rates vary by client, campaign type, and volume, and larger accounts can access managed-service arrangements alongside newer pricing levers such as first-party data onboarding fees and tiered self-serve pricing. Criteo's core technical differentiator has long been its access to large volumes of first-party commerce and shopper behavior data from retail partners, combined with AI and machine learning models used for real-time bidding, product recommendation, and audience targeting, which the company positions as an alternative or complement to advertising on Google, Meta, and Amazon. Because Criteo is a large, established public company rather than an early-stage startup, its most relevant facts for buyers and researchers in 2026 are its retail media and commerce media platform positioning, its scale across thousands of advertiser and publisher relationships, its NASDAQ listing and quarterly earnings disclosures, and its ongoing evolution from a pure retargeting vendor into a broader commerce media infrastructure provider competing with retail media networks and other adtech platforms across the growing retail media advertising category.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd003f92f-254f-4157-a191-83c6cb343faa';

