-- ── croc ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$croc is a free, open-source command-line tool for securely transferring files and folders between two computers using a simple code phrase, without needing a local server, port forwarding, or shared cloud storage. It uses password-authenticated key exchange (PAKE) to establish an encryption key and then encrypts transfers with AES-256, relaying encrypted data through a relay server that cannot read the file contents. Created by developer Zack Scholl (schollz) and released on GitHub, croc supports Windows, macOS, and Linux, and can use the default public relay or a self-hosted one.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (no license fees)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Not applicable (open-source project maintained primarily by an individual developer and contributors, not a company)$q$, company_size),
  headquarters = COALESCE($q$Not applicable (open-source project; maintainer publicly associated with the United States)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$croc: Free Secure Command-Line File Transfer Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$croc is a free, open-source CLI tool for sending files securely between computers using PAKE encryption. See features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$croc is a free, open-source command-line utility for securely and easily transferring files and folders between two computers, created by developer Zack Scholl, GitHub username schollz, and published as the schollz/croc repository. It is designed to solve a common developer and power-user problem: sending a file from one machine to another, potentially across different networks or behind NAT and firewalls, without setting up a local server, configuring port forwarding, or uploading the file to a third-party cloud storage service first. To use croc, a sender runs a single command to offer a file, folder, or piece of text, and croc generates a short, human-readable code phrase; the recipient runs croc with that code phrase on their own machine, and the transfer begins automatically once both sides connect. Security is handled through password-authenticated key exchange (PAKE), a cryptographic protocol that lets two parties who share a weak, human-readable secret (the code phrase) derive a strong, one-time session key without ever transmitting the code phrase itself over the network, protecting against eavesdropping even on the relay path. Once the session key is established, croc encrypts both the file data and its metadata using AES-256 before sending it, so that the connection between sender and receiver is end-to-end encrypted. Because most consumer and corporate networks block inbound connections and prevent two arbitrary computers from connecting to each other directly, croc routes the already encrypted data through an intermediary relay server; the relay's only job is to pass encrypted bytes back and forth, and because the data is encrypted before it reaches the relay, the relay operator cannot read the file contents. croc defaults to using a public relay server operated by the project, but it also supports self-hosting a private relay, including via Docker, which organizations often do when they have policy concerns about routing files through a third-party public relay, or when a public relay is unreachable inside a restricted network such as certain VPNs. Typical configuration uses TCP ports in the 9009 to 9013 range, though users can customize ports as long as at least two are open. croc supports resuming interrupted transfers, sending multiple files or entire folders in a single operation, cross-platform use across Windows, macOS, and Linux, and can optionally route traffic through a proxy such as Tor for additional privacy, alongside IPv6-first connectivity with automatic IPv4 fallback. Because croc is a command-line tool rather than a graphical application, it is most popular with developers, system administrators, and technically comfortable users who want a fast, scriptable, and secure alternative to email attachments, USB drives, or general-purpose cloud storage for one-off or repeated file transfers between machines they control. As free and open-source software hosted on GitHub, croc has no company, pricing plans, or customer support organization behind it; support comes from the GitHub repository's issues and documentation, and installation is typically done through package managers such as Homebrew, Scoop, or apt, or by downloading a prebuilt binary from the project's GitHub releases page.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '996b4a9f-71f2-4b4d-b8aa-21fea76d6666';

