-- ── Cron ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cron (cron.com) was a next-generation calendar application for professionals and teams, founded in 2019 by Raphael Schaad and based in San Francisco. Notion acquired Cron in 2022, and in January 2024 the standalone Cron app was retired and its technology relaunched as Notion Calendar, an integrated calendar product within the Notion ecosystem. As of 2026, Cron as a separate, independently branded app is discontinued; Notion Calendar is its direct successor and the correct current product for anyone searching for what Cron became.$q$, short_description),
  pricing_model = COALESCE($q$Not applicable as a standalone product since 2024; its successor, Notion Calendar, is offered free and bundled with Notion accounts$q$, pricing_model),
  starting_price = COALESCE($q$Not applicable (discontinued; successor Notion Calendar is free to use)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Not applicable as a standalone company since its 2022 acquisition by Notion Labs, Inc.$q$, company_size),
  headquarters = COALESCE($q$Formerly San Francisco, California, United States (prior to its acquisition by Notion)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Cron Calendar App: History, Notion Acquisition and Status$q$, seo_title),
  seo_meta_description = COALESCE($q$Cron was a calendar app acquired by Notion in 2022 and relaunched as Notion Calendar in 2024. Learn its history, features, and current status.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cron, also known by its domain cron.com, was a calendar application built for professionals and teams, founded in 2019 by Swiss-born software engineer and designer Raphael Schaad. The company went through Y Combinator's 2020 batch and raised a 3.5 million dollar seed round in April 2020 before launching its calendar app in public beta in 2021, where it was subsequently named Product Hunt's productivity app of the year for 2021. Cron was based in San Francisco, California, and built its reputation on a fast, keyboard-driven, visually polished calendar experience that connected to Google Calendar and, later, other calendar providers, offering features such as command-bar-style keyboard shortcuts, world clock and multiple time zone support, availability sharing and scheduling links, meeting templates, and tight integration with video conferencing tools, positioning itself as a modern successor to earlier well-regarded calendar apps like Sunrise Calendar. In June 2022, Notion Labs, Inc. announced it was acquiring Cron in a deal reported to be worth an eight-figure sum, with founder Raphael Schaad and his team joining Notion; at the time of the acquisition, Notion said Cron would continue to operate as a standalone app for a transition period. That transition period ended in January 2024, when Notion officially retired the separate Cron brand and relaunched the product as Notion Calendar, an integrated calendar application built directly on Cron's underlying technology and design but now marketed and distributed as part of the broader Notion productivity suite, including deep integration with Notion databases and documents so that calendar events can link to and pull information from a user's Notion workspace. Because of this history, it is important to distinguish the Cron calendar app covered in this profile from the completely unrelated Unix and Linux cron job scheduler, a decades-old system utility used to run scheduled command-line tasks; the two share only a name and have no connection to each other. As of 2026, the Cron calendar app referenced here, cron.com, is discontinued as an independently branded, independently distributed product. Existing Cron users were transitioned to Notion Calendar, and new users looking for Cron as a calendar app are, in practice, looking for Notion Calendar, which remains actively developed and is offered free of charge as part of the Notion ecosystem, available as a desktop app for macOS and Windows, a mobile app for iOS and Android, and a web version, with continued support for connecting multiple Google and Outlook calendar accounts. For SEO, directory, and comparison purposes in 2026, any reference to Cron as a currently available, separately branded calendar product would be inaccurate; the historically accurate and currently useful framing is that Cron was the predecessor product and brand, Notion acquired it in 2022, and Notion Calendar is its actively maintained continuation today.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '812088ef-3fdd-41e2-b15a-3a9f36f05e57';

